head.script:
scwin.onpageload = function () {
    // 초기(Column2D) 데이터 — wrapper 의 단순 포맷
    var jsonData = {
        "data": [
            { "value": "490000", "label": "China"  },
            { "value": "340000", "label": "USA"    },
            { "value": "160000", "label": "Brazil" },
            { "value": "220000", "label": "Spain"  },
            { "value": "123000", "label": "India"  }
        ]
    };
    chart1.setJSONData(jsonData);
};

scwin.trigger1_onclick = function (e) {
    chart1.changeType("line");
};

scwin.trigger2_onclick = function (e) {
    chart1.changeType("funnel");
};

scwin.trigger3_onclick = function (e) {
    // 1) 먼저 wrapper 의 changeType 으로 native 차트 인스턴스를 waterfall2d 로 재생성
    chart1.changeType("waterfall2d");

    // 2) waterfall2d 전용 native 포맷 데이터 (issum/cumulative/chart 옵션 포함)
    var jsonData = {
        "chart": {
            "theme": "fusion",
            "caption": "Total Profit Calculation",
            "subcaption": "Last month",
            "yAxisname": "Amount (In USD)",
            "numberprefix": "$",
            "connectordashed": "1",
            "sumlabel": "Total {br} Profit"
        },
        "data": [
            { "label": "Online sales",    "value": "420000" },
            { "label": "Store Sales",     "value": "710000" },
            { "label": "Total Sales",     "issum": "1" },
            { "label": "Fixed Costs",     "value": "-250000" },
            { "label": "Variable Costs",  "value": "-156000" },
            { "label": "COGS",            "value": "-310000" },
            { "label": "Promotion Costs", "value": "-86000" },
            { "label": "Total Costs",     "issum": "1", "cumulative": "0" }
        ]
    };

    // 3) wrapper.setJSONData 는 native 포맷(issum/chart 등) 처리 불가.
    //    chart1.fc() 로 native FusionCharts 객체에 직접 주입 후 render.
    var fc = chart1.fc();
    fc.setJSONData(jsonData);
    fc.render();
};
